const checkpoints = [];

function parseJson(key) {
  try { return JSON.parse(localStorage.getItem(key) || 'null'); } catch (e) { return null; }
}
function parseDate(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}
function dateOnlyStr(d) {
  return d.toISOString().split('T')[0];
}

const roomSearch = parseJson('task1_roomSearchParams');
const choice = parseJson('task1_cheapestGardenBreakfastOption');
const rooms = parseJson('rooms') || [];
const ratePlans = parseJson('rate_plans') || [];
const bookings = parseJson('bookings') || [];

// --- CP1: Correct search for June Fri–Sun weekend, 2 adults, garden view with breakfast, price ascending ---
let correctSearch = false;
if (roomSearch) {
  const ci = parseDate(roomSearch.checkInDate);
  const co = parseDate(roomSearch.checkOutDate);
  if (ci && co) {
    const msPerNight = 24*60*60*1000;
    const nights = Math.round((co - ci) / msPerNight);
    const fri = ci.getDay() === 5; // Friday
    const sun = co.getDay() === 0; // Sunday
    const inJune = ci.getMonth() === 5 && co.getMonth() === 5; // June (0-based)
    const adultsOk = roomSearch.adults === 2;
    const childrenOk = roomSearch.children === 0;
    const filters = roomSearch.filters || {};
    const amenities = Array.isArray(filters.amenities) ? filters.amenities : [];
    const hasBreakfastAmenity = amenities.indexOf('breakfast_included') !== -1;
    const gardenView = filters.viewType === 'garden_view';
    const sortOk = roomSearch.sortBy === 'price_asc';
    correctSearch = nights === 2 && fri && sun && inJune && adultsOk && childrenOk && hasBreakfastAmenity && gardenView && sortOk;
  }
}
checkpoints.push({ passed: correctSearch, weight: 0.3 });

// Helper to find cheapest qualifying garden-view + breakfast rate plan for the searched dates
function findCheapestGardenBreakfast(ciStr, coStr, adults, children) {
  const ci = parseDate(ciStr);
  const co = parseDate(coStr);
  const msPerNight = 24*60*60*1000;
  let nights = 1;
  if (ci && co) {
    nights = Math.round((co - ci) / msPerNight);
    if (nights <= 0) nights = 1;
  }
  let best = null;
  rooms.forEach(room => {
    if (!room.isActive) return;
    if (room.viewType !== 'garden_view') return;
    if (typeof room.maxOccupancyAdults === 'number' && adults > room.maxOccupancyAdults) return;
    if (typeof room.maxOccupancyChildren === 'number' && typeof children === 'number' && children > room.maxOccupancyChildren) return;
    ratePlans.forEach(rp => {
      if (!rp.isActive) return;
      if (!rp.includesBreakfast) return;
      if (rp.roomId !== room.id) return;
      // availability window
      if (rp.availableStartDate && ci) {
        const as = parseDate(rp.availableStartDate);
        if (as && ci < as) return;
      }
      if (rp.availableEndDate && co) {
        const ae = parseDate(rp.availableEndDate);
        if (ae && co > ae) return;
      }
      // min/max stay
      if (typeof rp.minStayNights === 'number' && rp.minStayNights > 0 && nights < rp.minStayNights) return;
      if (typeof rp.maxStayNights === 'number' && rp.maxStayNights > 0 && nights > rp.maxStayNights) return;
      const total = rp.nightlyPrice * nights;
      const avg = total / nights;
      if (!best || avg < best.avgNightlyPrice) {
        best = {
          roomId: room.id,
          ratePlanId: rp.id,
          avgNightlyPrice: avg,
          totalPrice: total
        };
      }
    });
  });
  return best;
}

// --- CP2: Instrumented cheapest option truly matches the cheapest qualifying combo ---
let correctCheapest = false;
if (roomSearch && choice) {
  const best = findCheapestGardenBreakfast(roomSearch.checkInDate, roomSearch.checkOutDate, roomSearch.adults, roomSearch.children || 0);
  if (best) {
    const roomMatch = choice.roomId === best.roomId;
    const rpMatch = choice.ratePlanId === best.ratePlanId;
    correctCheapest = roomMatch && rpMatch;
  }
}
checkpoints.push({ passed: correctCheapest, weight: 0.3 });

// --- CP3: Booking exists for that room+ratePlan with correct dates/guests and is at payment step ---
let proceededToPayment = false;
if (roomSearch && choice) {
  const ciTarget = dateOnlyStr(parseDate(roomSearch.checkInDate));
  const coTarget = dateOnlyStr(parseDate(roomSearch.checkOutDate));
  bookings.forEach(b => {
    if (b.roomId !== choice.roomId) return;
    if (b.ratePlanId !== choice.ratePlanId) return;
    if (b.adults !== 2) return;
    if (b.children !== 0) return;
    if (b.status !== 'pending_payment') return;
    const bCi = parseDate(b.checkInDate);
    const bCo = parseDate(b.checkOutDate);
    if (!bCi || !bCo) return;
    if (dateOnlyStr(bCi) !== ciTarget) return;
    if (dateOnlyStr(bCo) !== coTarget) return;
    const msPerNight = 24*60*60*1000;
    const nights = Math.round((bCo - bCi) / msPerNight);
    if (nights !== 2) return;
    proceededToPayment = true;
  });
}
checkpoints.push({ passed: proceededToPayment, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseJson(key) {
  try { return JSON.parse(localStorage.getItem(key) || 'null'); } catch (e) { return null; }
}
function parseDate(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}
function dateOnly(d) { return d.toISOString().split('T')[0]; }

const search = parseJson('task2_timeSlotSearch');
const resDetails = parseJson('task2_reservationDetails');
const slots = parseJson('restaurant_time_slots') || [];
const reservations = parseJson('restaurant_reservations') || [];

// Baseline date is 2026-03-03; 14 days later is 2026-03-17
const baseline = parseDate('2026-03-03T00:00:00Z');
const targetDateOnly = '2026-03-17';

// --- CP1: Correct search parameters (date+14, partySize 4, indoor, 19:00–20:00 window) ---
let correctSearch = false;
if (search) {
  const srchDate = parseDate(search.reservationDate);
  if (srchDate) {
    const sameDate = dateOnly(srchDate) === targetDateOnly;
    const partyOk = search.partySize === 4;
    const seatingOk = search.seatingArea === 'indoor';
    const fromOk = search.fromTime === '19:00';
    const toOk = search.toTime === '20:00';
    correctSearch = sameDate && partyOk && seatingOk && fromOk && toOk;
  }
}
checkpoints.push({ passed: correctSearch, weight: 0.35 });

// --- CP2: Reservation at earliest available indoor slot in window with window-table preference and persisted ---
let correctReservation = false;
// Compute earliest eligible slot from static slots
const candidateSlots = slots.filter(s => {
  if (!s.isAvailable) return false;
  const d = parseDate(s.reservationDate);
  if (!d) return false;
  if (dateOnly(d) !== targetDateOnly) return false;
  if (s.seatingArea !== 'indoor') return false;
  if (s.availableCapacity < 4) return false;
  if (s.reservationTime < '19:00') return false;
  if (s.reservationTime > '20:00') return false;
  return true;
});
if (resDetails && candidateSlots.length > 0) {
  candidateSlots.sort((a,b) => a.reservationTime.localeCompare(b.reservationTime));
  const earliest = candidateSlots[0];
  const dRes = parseDate(resDetails.reservationDate);
  const timeOk = resDetails.reservationTime === earliest.reservationTime;
  const dateOk = dRes && dateOnly(dRes) === targetDateOnly;
  const partyOk = resDetails.partySize === 4;
  const seatingOk = resDetails.seatingArea === 'indoor';
  const tablePrefOk = resDetails.tableLocationPreference === 'window_table';
  const slotIdOk = resDetails.timeSlotId === earliest.id;
  const persisted = !!reservations.find(r => r.id === resDetails.reservationId && r.timeSlotId === earliest.id && r.partySize === 4 && r.seatingArea === 'indoor' && r.reservationTime === earliest.reservationTime && dateOnly(parseDate(r.reservationDate)) === targetDateOnly);
  correctReservation = timeOk && dateOk && partyOk && seatingOk && tablePrefOk && slotIdOk && persisted;
}
checkpoints.push({ passed: correctReservation, weight: 0.65 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseJson(key) {
  try { return JSON.parse(localStorage.getItem(key) || 'null'); } catch (e) { return null; }
}
function parseDate(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}
function dateOnly(d) { return d.toISOString().split('T')[0]; }

const searchParams = parseJson('task3_offerSearchParams');
const topOfferId = localStorage.getItem('task3_topOfferId');
const offers = parseJson('offers') || [];
const bookings = parseJson('bookings') || [];

// --- CP1: Correct offer search filters and sorting ---
let correctSearch = false;
if (searchParams) {
  const filt = searchParams.filters || {};
  const spaOk = filt.includesSpaAccess === true;
  const lateOk = filt.includesLateCheckout === true;
  const hasMax = typeof filt.maxNightlyRate === 'number' && filt.maxNightlyRate <= 400;
  const sortOk = !searchParams.sortBy || searchParams.sortBy === 'guest_rating_desc';
  correctSearch = spaOk && lateOk && hasMax && sortOk;
}
checkpoints.push({ passed: correctSearch, weight: 0.4 });

// Determine highest-rated qualifying offer under $400/night
const qualifyingOffers = offers.filter(o => {
  if (!o.isActive) return false;
  if (!o.includesSpaAccess || !o.includesLateCheckout) return false;
  if (typeof o.nightlyRate !== 'number' || o.nightlyRate > 400) return false;
  return true;
});
qualifyingOffers.sort((a,b) => {
  const ra = typeof a.guestRating === 'number' ? a.guestRating : 0;
  const rb = typeof b.guestRating === 'number' ? b.guestRating : 0;
  if (rb !== ra) return rb - ra;
  return a.nightlyRate - b.nightlyRate;
});
const bestOffer = qualifyingOffers[0] || null;

// --- CP2: Selected offer ID matches the highest-rated qualifying offer ---
let correctTopOffer = false;
if (bestOffer && topOfferId) {
  correctTopOffer = topOfferId === bestOffer.id;
}
checkpoints.push({ passed: correctTopOffer, weight: 0.3 });

// --- CP3: Booking for that offer: 2 nights, 2 adults, Friday next month ---
// Baseline: 2026-03-03; next month is April 2026
let correctBooking = false;
if (bestOffer && topOfferId) {
  const candidateBookings = bookings.filter(b => b.offerId === bestOffer.id && b.source === 'offers' && b.adults === 2 && b.children === 0 && b.nights === 2);
  candidateBookings.forEach(b => {
    const ci = parseDate(b.checkInDate);
    const co = parseDate(b.checkOutDate);
    if (!ci || !co) return;
    const monthOk = ci.getMonth() === 3 && ci.getFullYear() === 2026; // April 2026 (0-based month)
    const fridayOk = ci.getDay() === 5; // Friday
    const msPerNight = 24*60*60*1000;
    const nights = Math.round((co - ci)/msPerNight);
    if (monthOk && fridayOk && nights === 2) {
      correctBooking = true;
    }
  });
}
checkpoints.push({ passed: correctBooking, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseJson(key) {
  try { return JSON.parse(localStorage.getItem(key) || 'null'); } catch (e) { return null; }
}
function parseDate(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

const giftCardTypes = parseJson('gift_card_types') || [];
const cartItems = parseJson('cart_items') || [];

function getTypeById(id) {
  return giftCardTypes.find(t => t.id === id) || null;
}

// Baseline date 2026-03-03
const baseline = parseDate('2026-03-03T00:00:00Z');

// Find items that are restaurant gift cards, email delivery, amount 150, qty 1
const primaryQualifying = cartItems.filter(it => {
  if (it.itemType !== 'gift_card') return false;
  if (it.amount !== 150) return false;
  if (it.deliveryMethod !== 'email') return false;
  if (it.quantity !== 1) return false;
  const type = getTypeById(it.giftCardTypeId);
  if (!type || type.code !== 'restaurant') return false;
  return true;
});

// --- CP1: At least one correctly typed restaurant email gift card for $150 in cart ---
const hasCorrectBaseItem = primaryQualifying.length > 0;
checkpoints.push({ passed: hasCorrectBaseItem, weight: 0.5 });

// --- CP2: Among those, at least one is scheduled ~7 days from baseline and has recipient details ---
let hasCorrectSendAndRecipient = false;
primaryQualifying.forEach(it => {
  if (!it.sendDate) return;
  const send = parseDate(it.sendDate);
  if (!send || !baseline) return;
  const diffDays = Math.round((send - baseline) / (24*60*60*1000));
  const sendOk = diffDays === 7;
  const recipientOk = !!(it.recipientEmail && String(it.recipientEmail).length > 0);
  if (sendOk && recipientOk) {
    hasCorrectSendAndRecipient = true;
  }
});
checkpoints.push({ passed: hasCorrectSendAndRecipient, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseJson(key) {
  try { return JSON.parse(localStorage.getItem(key) || 'null'); } catch (e) { return null; }
}
function parseDate(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}
function dateOnly(d) { return d.toISOString().split('T')[0]; }

const inquiries = parseJson('meeting_event_inquiries') || [];

// Target event date exactly one month after 2026-03-03 is 2026-04-03
const targetDateOnly = '2026-04-03';

const qualifying = inquiries.filter(inq => {
  if (inq.eventType !== 'corporate_meeting') return false;
  if (inq.attendeeCount !== 20) return false;
  const d = parseDate(inq.eventDate);
  if (!d || dateOnly(d) !== targetDateOnly) return false;
  if (inq.startTime !== '09:00') return false;
  if (inq.endTime !== '13:00') return false;
  const am = Array.isArray(inq.amenities) ? inq.amenities : [];
  const hasProjector = am.indexOf('projector') !== -1;
  const hasScreen = am.indexOf('screen') !== -1;
  const hasCoffee = am.indexOf('coffee_break') !== -1;
  return hasProjector && hasScreen && hasCoffee;
});

// --- CP1: Inquiry exists matching all criteria ---
const hasMatchingInquiry = qualifying.length > 0;
checkpoints.push({ passed: hasMatchingInquiry, weight: 0.6 });

// --- CP2: Such inquiry has been submitted (status = 'submitted') ---
let submittedOk = false;
qualifying.forEach(inq => {
  if (inq.status === 'submitted') submittedOk = true;
});
checkpoints.push({ passed: submittedOk, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseJson(key) {
  try { return JSON.parse(localStorage.getItem(key) || 'null'); } catch (e) { return null; }
}

const filterParams = parseJson('task6_menuFilterParams');
const menuItems = parseJson('menu_items') || [];
const plans = parseJson('dinner_plans') || [];
const planItemsAll = parseJson('dinner_plan_items') || [];
const currentPlanId = localStorage.getItem('current_dinner_plan_id');

// --- CP1: Menu was filtered for dinner & vegetarian items ---
let correctFilter = false;
if (filterParams) {
  const mealOk = filterParams.mealType === 'dinner';
  const filt = filterParams.filters || {};
  const vegOk = filt.isVegetarian === true;
  correctFilter = mealOk && vegOk;
}
checkpoints.push({ passed: correctFilter, weight: 0.3 });

// Find current plan and its items
const plan = plans.find(p => p.id === currentPlanId) || null;
const planItems = plan ? planItemsAll.filter(pi => pi.dinnerPlanId === plan.id) : [];

function findMenuItem(id) {
  return menuItems.find(m => m.id === id) || null;
}

let structureOk = false;
if (plan && planItems.length > 0) {
  let appCount = 0;
  let mainCount = 0;
  let dessertCount = 0;
  let totalQty = 0;
  let allQualifying = true;

  planItems.forEach(pi => {
    const mi = findMenuItem(pi.menuItemId);
    if (!mi) { allQualifying = false; return; }
    const qty = typeof pi.quantity === 'number' ? pi.quantity : 1;
    totalQty += qty;
    // All items must be vegetarian dinner/all_day
    const veg = mi.isVegetarian === true;
    const mealOk = mi.mealType === 'dinner' || mi.mealType === 'all_day';
    if (!veg || !mealOk) {
      allQualifying = false;
      return;
    }
    if (mi.courseType === 'appetizer') {
      if (mi.price < 15) appCount += qty; else allQualifying = false;
    } else if (mi.courseType === 'main') {
      if (mi.price < 30) mainCount += qty; else allQualifying = false;
    } else if (mi.courseType === 'dessert') {
      if (mi.price < 12) dessertCount += qty; else allQualifying = false;
    } else {
      // Any other course type breaks the exact-structure requirement
      allQualifying = false;
    }
  });

  if (allQualifying && totalQty === 4 && appCount === 1 && mainCount === 2 && dessertCount === 1) {
    structureOk = true;
  }
}
checkpoints.push({ passed: structureOk, weight: 0.5 });

// --- CP3: Plan was explicitly saved (has a non-empty name) ---
let savedOk = false;
if (plan && typeof plan.name === 'string' && plan.name.trim().length > 0) {
  savedOk = true;
}
checkpoints.push({ passed: savedOk, weight: 0.2 });

return checkoints = checkpoints, checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseJson(key) {
  try { return JSON.parse(localStorage.getItem(key) || 'null'); } catch (e) { return null; }
}
function parseDate(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}
function dateOnly(d) { return d.toISOString().split('T')[0]; }

const search = parseJson('task7_roomSearchParams');
const rooms = parseJson('rooms') || [];
const ratePlans = parseJson('rate_plans') || [];
const comparisons = parseJson('room_comparisons') || [];
const bookings = parseJson('bookings') || [];
const currentComparisonId = localStorage.getItem('current_room_comparison_id');

// --- CP1: Correct room search (3-night Mon–Thu next month, 1 adult, max nightly rate 250, price asc) ---
let correctSearch = false;
if (search) {
  const ci = parseDate(search.checkInDate);
  const co = parseDate(search.checkOutDate);
  if (ci && co) {
    const ms = 24*60*60*1000;
    const nights = Math.round((co - ci)/ms);
    const mon = ci.getDay() === 1;
    const thu = co.getDay() === 4;
    // Next month relative to baseline March 2026 is April 2026
    const inNextMonth = ci.getMonth() === 3 && ci.getFullYear() === 2026;
    const adultsOk = search.adults === 1;
    const childrenOk = search.children === 0;
    const filters = search.filters || {};
    const maxPriceOk = typeof filters.maxPricePerNight === 'number' && filters.maxPricePerNight === 250;
    const sortOk = search.sortBy === 'price_asc';
    correctSearch = nights === 3 && mon && thu && inNextMonth && adultsOk && childrenOk && maxPriceOk && sortOk;
  }
}
checkpoints.push({ passed: correctSearch, weight: 0.35 });

// Helper: cheapest nightly rate for a room under constraints
function cheapestNightlyForRoom(room, ci, co) {
  const ms = 24*60*60*1000;
  let nights = 1;
  if (ci && co) {
    nights = Math.round((co - ci)/ms);
    if (nights <= 0) nights = 1;
  }
  let best = null;
  ratePlans.forEach(rp => {
    if (!rp.isActive) return;
    if (rp.roomId !== room.id) return;
    // date windows
    if (rp.availableStartDate && ci) {
      const as = parseDate(rp.availableStartDate);
      if (as && ci < as) return;
    }
    if (rp.availableEndDate && co) {
      const ae = parseDate(rp.availableEndDate);
      if (ae && co > ae) return;
    }
    // min/max stay
    if (typeof rp.minStayNights === 'number' && rp.minStayNights > 0 && nights < rp.minStayNights) return;
    if (typeof rp.maxStayNights === 'number' && rp.maxStayNights > 0 && nights > rp.maxStayNights) return;
    if (!best || rp.nightlyPrice < best.nightlyPrice) {
      best = { nightlyPrice: rp.nightlyPrice, ratePlanId: rp.id };
    }
  });
  return best;
}

// Build the list of first three cheapest rooms under 250 for the searched dates
let firstThreeRoomIds = [];
let ci = null, co = null;
if (search) {
  ci = parseDate(search.checkInDate);
  co = parseDate(search.checkOutDate);
}
if (ci && co) {
  const candidates = [];
  rooms.forEach(room => {
    if (!room.isActive) return;
    if (typeof room.maxOccupancyAdults === 'number' && search.adults > room.maxOccupancyAdults) return;
    const cheapest = cheapestNightlyForRoom(room, ci, co);
    if (!cheapest) return;
    if (cheapest.nightlyPrice > 250) return;
    candidates.push({ roomId: room.id, nightlyPrice: cheapest.nightlyPrice, ratePlanId: cheapest.ratePlanId });
  });
  candidates.sort((a,b) => a.nightlyPrice - b.nightlyPrice);
  firstThreeRoomIds = candidates.slice(0,3).map(c => c.roomId);
}

// --- CP2: Room comparison contains exactly those first three rooms ---
let comparisonCorrect = false;
if (firstThreeRoomIds.length === 3 && currentComparisonId) {
  const comp = comparisons.find(c => c.id === currentComparisonId) || null;
  if (comp && Array.isArray(comp.roomIds)) {
    const ids = comp.roomIds;
    const allPresent = firstThreeRoomIds.every(id => ids.indexOf(id) !== -1);
    comparisonCorrect = allPresent && ids.length === firstThreeRoomIds.length;
  }
}
checkpoints.push({ passed: comparisonCorrect, weight: 0.35 });

// --- CP3: Booking created for room with largest bed among compared, tie-broken by lowest price ---
function bedRank(bedType) {
  const ranks = {
    king_plus_sofa_bed: 6,
    king: 5,
    queen: 4,
    double: 3,
    twin: 2,
    single: 1,
    sofa_bed: 0
  };
  return typeof ranks[bedType] === 'number' ? ranks[bedType] : -1;
}

let bookingCorrect = false;
if (firstThreeRoomIds.length === 3 && ci && co) {
  // Determine the best room by bed size then lowest nightly price
  const candidates = firstThreeRoomIds.map(roomId => {
    const room = rooms.find(r => r.id === roomId) || {};
    const cheapest = cheapestNightlyForRoom(room, ci, co) || { nightlyPrice: Infinity };
    return {
      roomId,
      bedRank: bedRank(room.bedType),
      nightlyPrice: cheapest.nightlyPrice
    };
  });
  candidates.sort((a,b) => {
    if (b.bedRank !== a.bedRank) return b.bedRank - a.bedRank;
    return a.nightlyPrice - b.nightlyPrice;
  });
  const bestRoomId = candidates[0] ? candidates[0].roomId : null;

  if (bestRoomId) {
    bookings.forEach(b => {
      if (b.roomId !== bestRoomId) return;
      if (b.adults !== 1) return;
      if (b.children !== 0) return;
      const bCi = parseDate(b.checkInDate);
      const bCo = parseDate(b.checkOutDate);
      if (!bCi || !bCo) return;
      const ms = 24*60*60*1000;
      const nights = Math.round((bCo - bCi)/ms);
      // Same next-month Mon–Thu pattern
      const mon = bCi.getDay() === 1;
      const thu = bCo.getDay() === 4;
      const monthOk = bCi.getMonth() === 3 && bCi.getFullYear() === 2026;
      if (nights === 3 && mon && thu && monthOk) {
        bookingCorrect = true;
      }
    });
  }
}
checkpoints.push({ passed: bookingCorrect, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

