}

const subs = parseJson('newsletter_subscriptions') || [];

// Qualifying subscription: room & restaurant interests, monthly, consentMarketing true
const qualifying = subs.filter(s => s.interestRoomOffers === true && s.interestRestaurantEvents === true && s.frequency === 'monthly' && s.consentMarketing === true);

// Single combined checkpoint for correct subscription
checkpoints.push({ passed: qualifying.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
